import React, { FunctionComponent } from "react";
import { ChoiceBreakdown } from "../stats";

export const NLBreakdown: FunctionComponent<ChoiceBreakdown> = ({
  place,
  placements,
  possiblePlaces,
  averagePlacement,
  consensus
}) => {
  // TODO: placement, placement avg
  const placement = <span>
    This option was ranked {ordinal(place + 1)} place out of {possiblePlaces} possible places.
  </span>;

  // const avgPlacement = <span>
  //   It was ranked {averagePlacement.toFixed(2)} on average.
  // </span>;

  // TODO: consensus?
  const agreement = consensus > 0.75 ? (
    <span>
      Participants mostly agreed on this.
    </span>
  ) : consensus < 0.25 ? (
    <span>
      This options was divisive.
    </span>
  ) : <></>;

  const filteredPlacements = placements
    .map((count, place) => [count, place])
    .filter((_, i) => placements[i] > 0);

  let placementReport: string;
  
  if (filteredPlacements.length === 1) {
    placementReport = `Everyone ranked this option ${ordinal(filteredPlacements[0][1])}.`;
  } else {
    const [headCount, headRank] = filteredPlacements[0];
    const [tailCount, tailRank] = filteredPlacements[filteredPlacements.length - 1];
    const middle = filteredPlacements.length > 2 ? (
      filteredPlacements.slice(1, filteredPlacements.length - 1)
        .map(([ count, place ]) => `, ${count} ranked it ${ordinal(place)}`)
        .join("")
    ) : "";
    
    placementReport =
      `${[headCount]} participants ranked this option ${ordinal(headRank)}` +
      middle +
      (middle.length > 0 ? "," : "") +
      ` and ${tailCount} ranked it ${tailRank}.`

  }
  // TODO: sentiment
  return (
    <p>
      {placement} {/*{avgPlacement}*/} {agreement} {placementReport}
    </p>
  )
};

const ordinal = (num: number): string => {
  const tenMod = num % 10;
  const hundMod = num % 100;
  if (tenMod === 1 && hundMod !== 11) {
    return `${num}st`;
  }
  if (tenMod === 2 && hundMod !== 12) {
    return `${num}nd`;
  }
  if (tenMod === 3 && hundMod !== 13) {
    return `${num}rd`;
  }

  return `${num}th`;
}
